"use client";

import { useState } from "react";
import { submitEventRequest } from "@/app/actions/requests";
import { X, Send, HelpCircle, CheckCircle2 } from "lucide-react";

export default function RequestEventModal({ isOpen, onClose }: { isOpen: boolean; onClose: () => void }) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  if (!isOpen) return null;

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    const formData = new FormData(e.currentTarget);
    const result = await submitEventRequest(formData);

    if (result?.error) {
      setError(result.error);
      setIsSubmitting(false);
    } else {
      setIsSuccess(true);
      setTimeout(() => { setIsSuccess(false); onClose(); }, 3000);
    }
  }

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="bg-zinc-950 border border-zinc-800 w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        
        <div className="flex items-center justify-between border-b border-zinc-900 px-6 py-4">
          <div className="flex items-center gap-2">
            <HelpCircle className="w-5 h-5 text-emerald-500" />
            <h2 className="text-sm font-bold uppercase tracking-widest text-zinc-300">Request an Event</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-zinc-900 rounded-full transition-colors"><X className="w-5 h-5 text-zinc-500" /></button>
        </div>

        <div className="p-8 text-center">
          {isSuccess ? (
            <div className="py-10 space-y-4">
              <CheckCircle2 className="w-12 h-12 text-emerald-500 mx-auto" />
              <h3 className="text-xl font-bold text-white">Got it!</h3>
              <p className="text-zinc-400 text-sm">We'll review your request and add it to the database shortly.</p>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6 text-left">
              <p className="text-sm text-zinc-400">Can't find an event? Tell us what you're waiting for and we'll track it.</p>
              
              <input type="text" name="nickname" className="hidden" tabIndex={-1} autoComplete="off" />

              <div>
                <label className="block text-[10px] font-bold uppercase text-zinc-500 mb-2 ml-1">Event Name</label>
                <input required name="eventTitle" placeholder="e.g. Next Apple Event" className="w-full bg-black border border-zinc-800 rounded-xl px-4 py-3 text-white focus:border-emerald-500/50 outline-none" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-bold uppercase text-zinc-500 mb-2 ml-1">Date (If known)</label>
                  <input name="eventDate" placeholder="e.g. Fall 2026" className="w-full bg-black border border-zinc-800 rounded-xl px-4 py-3 text-white outline-none" />
                </div>
                <div>
                  <label className="block text-[10px] font-bold uppercase text-zinc-500 mb-2 ml-1">Source URL</label>
                  <input name="eventSource" placeholder="Link to news" className="w-full bg-black border border-zinc-800 rounded-xl px-4 py-3 text-white outline-none" />
                </div>
              </div>

              {error && <p className="text-red-400 text-xs font-bold">{error}</p>}

              <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-500 hover:bg-emerald-400 text-black font-black uppercase tracking-widest py-4 rounded-2xl flex items-center justify-center gap-2 transition-all">
                {isSubmitting ? "Sending..." : <><Send className="w-4 h-4" /> Send Request</>}
              </button>
              <p className="text-[10px] text-center text-zinc-600 uppercase font-bold">No account required. We verify all requests.</p>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}